   905в†’## 4.2.7 Route Utilization Service (NEW v2.1)
   906в†’
   907в†’### 4.2.7.1 Purpose
   908в†’
   909в†’Provide route-specific daily mileage rates for accurate long-term projections. Using fleet-wide averages can result in 60,000+ km projection error over 12 years.
   910в†’
   911в†’### 4.2.7.2 Implementation
   912в†’
   913в†’```typescript
   914в†’interface RouteUtilizationProfile {
   915в†’  id: string;
   916в†’  routeId: string;
   917в†’  effectiveDate: Date;
   918в†’  
   919в†’  weekdayKm: number;
   920в†’  saturdayKm?: number;
   921в†’  sundayKm?: number;
   922в†’  holidayKm?: number;
   923в†’  
   924в†’  peakSeasonMultiplier: number;
   925в†’  offPeakMultiplier: number;
   926в†’  
   927в†’  confidence: 'HIGH' | 'MEDIUM' | 'LOW' | 'ESTIMATED';
   928в†’}
   929в†’
   930в†’class RouteUtilizationService {
   931в†’  constructor(private db: Database) {}
   932в†’  
   933в†’  /**
   934в†’   * Get utilization profile for a route
   935в†’   */
   936в†’  async getProfile(routeId: string, asOfDate?: Date): Promise<RouteUtilizationProfile | null> {
   937в†’    const date = asOfDate || new Date();
   938в†’    
   939в†’    const profile = await this.db
   940в†’      .select()
   941в†’      .from(routeUtilizationProfiles)
   942в†’      .where(and(
   943в†’        eq(routeUtilizationProfiles.routeId, routeId),
   944в†’        lte(routeUtilizationProfiles.effectiveDate, date)
   945в†’      ))
   946в†’      .orderBy(desc(routeUtilizationProfiles.effectiveDate))
   947в†’      .limit(1);
   948в†’    
   949в†’    return profile[0] || null;
   950в†’  }
   951в†’  
   952в†’  /**
   953в†’   * Calculate expected daily km for a train based on typical route assignment
   954в†’   */
   955в†’  async calculateDailyRate(
   956в†’    trainId: string, 
   957в†’    targetDate: Date
   958в†’  ): Promise<{ dailyKm: number; source: string; confidence: string }> {
   959в†’    // 1. Check for explicit route assignment
   960в†’    const assignment = await this.getTypicalRouteAssignment(trainId);
   961в†’    
   962в†’    if (assignment) {
   963в†’      const profile = await this.getProfile(assignment.routeId, targetDate);
   964в†’      if (profile) {
   965в†’        const dayType = this.getDayType(targetDate);
   966в†’        const baseKm = this.getKmForDayType(profile, dayType);
   967в†’        const seasonalMultiplier = this.getSeasonalMultiplier(profile, targetDate);
   968в†’        
   969в†’        return {
   970в†’          dailyKm: Math.round(baseKm * seasonalMultiplier),
   971в†’          source: `route:${assignment.routeId}`,
   972в†’          confidence: profile.confidence
   973в†’        };
   974в†’      }
   975в†’    }
   976в†’    
   977в†’    // 2. Fall back to fleet average
   978в†’    const train = await this.db
   979в†’      .select({ fleetId: trains.fleetId })
   980в†’      .from(trains)
   981в†’      .where(eq(trains.id, trainId))
   982в†’      .limit(1);
   983в†’    
   984в†’    if (train[0]) {
   985в†’      const fleetAverage = await this.getFleetAverage(train[0].fleetId);
   986в†’      return {
   987в†’        dailyKm: fleetAverage,
   988в†’        source: 'fleet_average',
   989в†’        confidence: 'LOW'
   990в†’      };
   991в†’    }
   992в†’    
   993в†’    // 3. System default
   994в†’    return {
   995в†’      dailyKm: 250,  // Conservative default
   996в†’      source: 'system_default',
   997в†’      confidence: 'ESTIMATED'
   998в†’    };
   999в†’  }
  1000в†’  
  1001в†’  /**
  1002в†’   * Project mileage for a train over a time horizon
  1003в†’   */
  1004в†’  async projectMileage(
  1005в†’    trainId: string,
  1006в†’    startDate: Date,
  1007в†’    horizonDays: number
  1008в†’  ): Promise<{ date: Date; projectedKm: number; cumulativeKm: number }[]> {
  1009в†’    const train = await this.db
  1010в†’      .select()
  1011в†’      .from(trains)
  1012в†’      .where(eq(trains.id, trainId))
  1013в†’      .limit(1);
  1014в†’    
  1015в†’    if (!train[0]) {
  1016в†’      throw new NotFoundError(`Train ${trainId} not found`);
  1017в†’    }
  1018в†’    
  1019в†’    let cumulativeKm = train[0].currentMileageKm;
  1020в†’    const projections: { date: Date; projectedKm: number; cumulativeKm: number }[] = [];
  1021в†’    
  1022в†’    for (let day = 0; day < horizonDays; day++) {
  1023в†’      const targetDate = addDays(startDate, day);
  1024в†’      const { dailyKm } = await this.calculateDailyRate(trainId, targetDate);
  1025в†’      
  1026в†’      cumulativeKm += dailyKm;
  1027в†’      projections.push({
  1028в†’        date: targetDate,
  1029в†’        projectedKm: dailyKm,
  1030в†’        cumulativeKm
  1031в†’      });
  1032в†’    }
  1033в†’    
  1034в†’    return projections;
  1035в†’  }
  1036в†’  
  1037в†’  private async getTypicalRouteAssignment(trainId: string): Promise<{ routeId: string } | null> {
  1038в†’    // Look at recent run assignments to determine typical route
  1039в†’    const recentAssignments = await this.db
  1040в†’      .select({ routeId: runAssignments.routeId, count: count() })
  1041в†’      .from(runAssignments)
  1042в†’      .where(and(
  1043в†’        eq(runAssignments.trainId, trainId),
  1044в†’        gte(runAssignments.assignmentDate, addDays(new Date(), -30))
  1045в†’      ))
  1046в†’      .groupBy(runAssignments.routeId)
  1047в†’      .orderBy(desc(count()))
  1048в†’      .limit(1);
  1049в†’    
  1050в†’    return recentAssignments[0] || null;
  1051в†’  }
  1052в†’  
  1053в†’  private async getFleetAverage(fleetId: string): Promise<number> {
  1054в†’    // Calculate from recent mileage readings
  1055в†’    const result = await this.db
  1056в†’      .select({ avgDaily: avg(mileageReadings.dailyKm) })
  1057в†’      .from(mileageReadings)
  1058в†’      .innerJoin(trains, eq(mileageReadings.trainId, trains.id))
  1059в†’      .where(and(
  1060в†’        eq(trains.fleetId, fleetId),
  1061в†’        gte(mileageReadings.readingDate, addDays(new Date(), -30)),
  1062в†’        eq(mileageReadings.validationStatus, 'VALID')
  1063в†’      ));
  1064в†’    
  1065в†’    return Math.round(result[0]?.avgDaily || 250);
  1066в†’  }
  1067в†’  
  1068в†’  private getKmForDayType(profile: RouteUtilizationProfile, dayType: string): number {
  1069в†’    switch (dayType) {
  1070в†’      case 'SATURDAY': return profile.saturdayKm || profile.weekdayKm * 0.8;
  1071в†’      case 'SUNDAY': return profile.sundayKm || profile.weekdayKm * 0.7;
  1072в†’      case 'HOLIDAY': return profile.holidayKm || profile.weekdayKm * 0.6;
  1073в†’      default: return profile.weekdayKm;
  1074в†’    }
  1075в†’  }
  1076в†’  
  1077в†’  private getSeasonalMultiplier(profile: RouteUtilizationProfile, date: Date): number {
  1078в†’    // TODO: Integrate with season calendar
  1079в†’    const month = date.getMonth();
  1080в†’    // Peak season: CNY (Jan-Feb), School holidays (Jun, Nov-Dec)
  1081в†’    const peakMonths = [0, 1, 5, 10, 11];
  1082в†’    return peakMonths.includes(month) ? profile.peakSeasonMultiplier : profile.offPeakMultiplier;
  1083в†’  }
  1084в†’  
  1085в†’  private getDayType(date: Date): string {
  1086в†’    const dayOfWeek = date.getDay();
  1087в†’    if (dayOfWeek === 0) return 'SUNDAY';
  1088в†’    if (dayOfWeek === 6) return 'SATURDAY';
  1089в†’    return 'WEEKDAY';
  1090в†’  }
  1091в†’}
  1092в†’```
