  1845в†’      const track = this.findAvailableTrack(
  1846в†’        targetDate,
  1847в†’        pmType.trackType,
  1848в†’        pmType.minTrackDays,
  1849в†’        trackAvailability
  1850в†’      );
  1851в†’      
  1852в†’      if (!track) continue;
  1853в†’      
  1854в†’      // Check labor capacity
  1855в†’      const laborOk = this.checkLaborCapacity(
  1856в†’        targetDate,
  1857в†’        pmType.estimatedHours,
  1858в†’        laborCapacity
  1859в†’      );
  1860в†’      
  1861в†’      if (!laborOk) continue;
  1862в†’      
  1863в†’      // Check material availability
  1864в†’      const materialCheck = await this.checkMaterialAvailability(
  1865в†’        pm,
  1866в†’        targetDate,
  1867в†’        materialPositions
  1868в†’      );
  1869в†’      
  1870в†’      if (materialCheck.blocked) {
  1871в†’        // Within hard constraint window - cannot schedule
  1872в†’        if (this.isWithinHardWindow(targetDate)) {
  1873в†’          return {
  1874в†’            scheduled: null,
  1875в†’            reason: `Material unavailable: ${materialCheck.missingParts.join(', ')}`,
  1876в†’            suggestedDate: materialCheck.suggestedDate,
  1877в†’            materialWarning: {
  1878в†’              pmId: pm.id,
  1879в†’              trainId: pm.trainId,
  1880в†’              missingParts: materialCheck.missingParts,
  1881в†’              expectedAvailability: materialCheck.expectedDelivery
  1882в†’            }
  1883в†’          };
  1884в†’        }
  1885в†’        // Soft constraint window - add warning but continue
  1886в†’        continue;
  1887в†’      }
  1888в†’      
  1889в†’      // Schedule found!
  1890в†’      return {
  1891в†’        scheduled: {
  1892в†’          pmId: pm.id,
  1893в†’          trainId: pm.trainId,
  1894в†’          pmTypeId: pmType.id,
  1895в†’          targetDate,
  1896в†’          trackId: track.id,
  1897в†’          assignedHours: pmType.estimatedHours,
  1898в†’          constraintStart: pm.constraintStart,
  1899в†’          constraintEnd: pm.constraintEnd
  1900в†’        },
  1901в†’        reason: null,
  1902в†’        materialWarning: materialCheck.warning
  1903в†’      };
  1904в†’    }
  1905в†’    
  1906в†’    // No valid slot found
  1907в†’    return {
  1908в†’      scheduled: null,
  1909в†’      reason: 'No available slot within compliance window',
  1910в†’      suggestedDate: addDays(pm.constraintEnd, 7)
  1911в†’    };
  1912в†’  }
  1913в†’  
  1914в†’  private async checkMaterialAvailability(
  1915в†’    pm: PendingPM,
  1916в†’    targetDate: Date,
  1917в†’    materialPositions: MaterialPosition[]
  1918в†’  ): Promise<MaterialCheckResult> {
  1919в†’    const requirements = await this.getPMRequirements(pm.pmType.id);
  1920в†’    const missingParts: string[] = [];
  1921в†’    let earliestDelivery: Date | null = null;
  1922в†’    
  1923в†’    for (const req of requirements) {
  1924в†’      if (req.criticality === 'CONSUMABLE') continue;
  1925в†’      
  1926в†’      const position = materialPositions.find(
  1927в†’        p => p.partNumber === req.partNumber && p.depotId === pm.depotId
  1928в†’      );
  1929в†’      
  1930в†’      const available = position?.quantityAvailable || 0;
  1931в†’      
  1932в†’      if (available < req.quantityPerPM) {
  1933в†’        if (req.criticality === 'BLOCKING') {
  1934в†’          missingParts.push(req.partNumber);
  1935в†’          
  1936в†’          if (position?.nextDeliveryDate) {
  1937в†’            const delivery = new Date(position.nextDeliveryDate);
  1938в†’            if (!earliestDelivery || delivery < earliestDelivery) {
  1939в†’              earliestDelivery = delivery;
  1940в†’            }
  1941в†’          }
  1942в†’        }
  1943в†’      }
  1944в†’    }
  1945в†’    
  1946в†’    return {
  1947в†’      blocked: missingParts.length > 0 && 
  1948в†’               this.isWithinHardWindow(targetDate),
  1949в†’      missingParts,
  1950в†’      expectedDelivery: earliestDelivery,
  1951в†’      suggestedDate: earliestDelivery 
  1952в†’        ? addDays(earliestDelivery, 1)
  1953в†’        : null,
  1954в†’      warning: missingParts.length > 0 ? {
  1955в†’        type: 'LOW_STOCK',
  1956в†’        parts: missingParts,
  1957в†’        message: `Parts may be unavailable: ${missingParts.join(', ')}`
  1958в†’      } : null
  1959в†’    };
  1960в†’  }
  1961в†’}
