  1964в†’### 4.4.3 PM Schedule Management Service
  1965в†’
  1966в†’Handles manual PM modifications (drag-and-drop, manual reschedules) with full validation including Maximo status locks.
  1967в†’
  1968в†’```typescript
  1969в†’/**
  1970в†’ * Service for manual PM schedule modifications.
  1971в†’ * 
  1972в†’ * CRITICAL: All modifications MUST validate against Maximo status to prevent
  1973в†’ * race conditions with in-progress work orders. The PMEditValidator from the
  1974в†’ * Integration layer (Part 7) provides this validation.
  1975в†’ * 
  1976в†’ * Operational reality (Maximo) MUST override planning data (MMS).
  1977в†’ */
  1978в†’class PMScheduleManagementService {
  1979в†’  private pmEditValidator: PMEditValidator;  // From Part 7
  1980в†’  private auditLogger: AuditLogger;
  1981в†’  
  1982в†’  /**
  1983в†’   * Move a PM to a new date (e.g., from canvas drag-and-drop).
  1984в†’   * 
  1985в†’   * @throws MaximoLockError if PM is in-progress in Maximo
  1986в†’   * @throws ComplianceWindowError if new date is outside allowed window
  1987в†’   * @throws TrackConflictError if track is occupied on new date
  1988в†’   */
  1989в†’  async movePM(
  1990в†’    pmId: string,
  1991в†’    newTargetDate: Date,
  1992в†’    newTrackId: string | null,
  1993в†’    userId: string
  1994в†’  ): Promise<PMScheduleRecord> {
  1995в†’    
  1996в†’    // 1. CRITICAL: Validate Maximo status lock
  1997в†’    const editValidation = await this.pmEditValidator.validateEdit(pmId);
  1998в†’    
  1999в†’    if (!editValidation.valid) {
  2000в†’      throw new PMEditBlockedError(
  2001в†’        editValidation.reason,
  2002в†’        editValidation.message,
  2003в†’        {
  2004в†’          maximoStatus: editValidation.maximoStatus,
  2005в†’          maximoWonum: editValidation.maximoWonum,
  2006в†’          suggestion: editValidation.suggestion
  2007в†’        }
  2008в†’      );
  2009в†’    }
  2010в†’    
  2011в†’    // 2. Load PM with all relationships
  2012в†’    const pm = await this.db.query.pmSchedule.findFirst({
  2013в†’      where: eq(pmSchedule.id, pmId),
  2014в†’      with: {
  2015в†’        pmType: true,
  2016в†’        train: true,
  2017в†’        assignedTrack: true
  2018в†’      }
  2019в†’    });
  2020в†’    
  2021в†’    if (!pm) {
  2022в†’      throw new NotFoundError('PM not found');
  2023в†’    }
  2024в†’    
  2025в†’    // 3. Validate compliance window
  2026в†’    if (newTargetDate < pm.constraintStart || newTargetDate > pm.constraintEnd) {
  2027в†’      throw new ComplianceWindowError(
  2028в†’        `Target date ${newTargetDate.toISOString().split('T')[0]} is outside compliance window`,
  2029в†’        {
  2030в†’          constraintStart: pm.constraintStart,
  2031в†’          constraintEnd: pm.constraintEnd,
  2032в†’          requestedDate: newTargetDate
  2033в†’        }
  2034в†’      );
  2035в†’    }
  2036в†’    
  2037в†’    // 4. Validate track availability (if track specified)
  2038в†’    if (newTrackId) {
  2039в†’      const conflict = await this.checkTrackConflict(
  2040в†’        newTrackId,
  2041в†’        newTargetDate,
  2042в†’        pm.pmType.minTrackDays,
  2043в†’        pmId  // Exclude self from conflict check
  2044в†’      );
  2045в†’      
  2046в†’      if (conflict) {
  2047в†’        throw new TrackConflictError(
  2048в†’          `Track ${conflict.trackNumber} is occupied by ${conflict.conflictingPMCode}`,
  2049в†’          conflict
  2050в†’        );
  2051в†’      }
  2052в†’    }
  2053в†’    
  2054в†’    // 5. Capture old state for audit
  2055в†’    const oldState = {
  2056в†’      targetDate: pm.targetDate,
  2057в†’      assignedTrackId: pm.assignedTrackId
  2058в†’    };
  2059в†’    
  2060в†’    // 6. Update PM schedule
  2061в†’    const updatedPM = await this.db.transaction(async (tx) => {
  2062в†’      // Update main record
  2063в†’      const [updated] = await tx.update(pmSchedule)
  2064в†’        .set({
  2065в†’          targetDate: newTargetDate,
  2066в†’          assignedTrackId: newTrackId ?? pm.assignedTrackId,
  2067в†’          updatedAt: new Date()
  2068в†’        })
  2069в†’        .where(eq(pmSchedule.id, pmId))
  2070в†’        .returning();
  2071в†’      
  2072в†’      // Record in history table
  2073в†’      await tx.insert(pmScheduleHistory).values({
  2074в†’        pmScheduleId: pmId,
  2075в†’        changeType: 'RESCHEDULE',
  2076в†’        fieldName: 'targetDate',
  2077в†’        oldValue: oldState.targetDate.toISOString(),
  2078в†’        newValue: newTargetDate.toISOString(),
  2079в†’        changedBy: userId,
  2080в†’        reason: 'Manual reschedule via canvas'
  2081в†’      });
  2082в†’      
  2083в†’      if (newTrackId && newTrackId !== pm.assignedTrackId) {
  2084в†’        await tx.insert(pmScheduleHistory).values({
  2085в†’          pmScheduleId: pmId,
  2086в†’          changeType: 'TRACK_REASSIGNMENT',
  2087в†’          fieldName: 'assignedTrackId',
  2088в†’          oldValue: oldState.assignedTrackId,
  2089в†’          newValue: newTrackId,
  2090в†’          changedBy: userId,
  2091в†’          reason: 'Track reassignment via canvas'
  2092в†’        });
  2093в†’      }
  2094в†’      
  2095в†’      return updated;
  2096в†’    });
  2097в†’    
  2098в†’    // 7. Update shadow record for Maximo sync
  2099в†’    await this.updateShadowRecord(pmId, {
  2100в†’      syncStatus: 'PENDING',
  2101в†’      pendingChanges: {
  2102в†’        targetDate: newTargetDate.toISOString(),
  2103в†’        trackId: newTrackId
  2104в†’      }
  2105в†’    });
  2106в†’    
  2107в†’    // 8. Audit log
  2108в†’    await this.auditLogger.log({
  2109в†’      action: 'PM_RESCHEDULED',
  2110в†’      entityType: 'PM_SCHEDULE',
  2111в†’      entityId: pmId,
  2112в†’      userId,
  2113в†’      changes: {
  2114в†’        targetDate: { old: oldState.targetDate, new: newTargetDate },
  2115в†’        assignedTrackId: { old: oldState.assignedTrackId, new: newTrackId }
  2116в†’      }
  2117в†’    });
  2118в†’    
  2119в†’    return updatedPM;
  2120в†’  }
