  2143в†’  /**
  2144в†’   * Check if a track has conflicts for the given date range.
  2145в†’   */
  2146в†’  private async checkTrackConflict(
  2147в†’    trackId: string,
  2148в†’    startDate: Date,
  2149в†’    durationDays: number,
  2150в†’    excludePmId?: string
  2151в†’  ): Promise<TrackConflict | null> {
  2152в†’    const endDate = addDays(startDate, durationDays);
  2153в†’    
  2154в†’    const conflictingPM = await this.db.query.pmSchedule.findFirst({
  2155в†’      where: and(
  2156в†’        eq(pmSchedule.assignedTrackId, trackId),
  2157в†’        excludePmId ? ne(pmSchedule.id, excludePmId) : undefined,
  2158в†’        or(
  2159в†’          // New PM overlaps existing PM's start
  2160в†’          and(
  2161в†’            lte(pmSchedule.targetDate, startDate),
  2162в†’            gte(sql`${pmSchedule.targetDate} + ${durationDays} * interval '1 day'`, startDate)
  2163в†’          ),
  2164в†’          // New PM overlaps existing PM's end
  2165в†’          and(
  2166в†’            lte(pmSchedule.targetDate, endDate),
  2167в†’            gte(sql`${pmSchedule.targetDate} + ${durationDays} * interval '1 day'`, startDate)
  2168в†’          )
  2169в†’        ),
  2170в†’        inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS'])
  2171в†’      ),
  2172в†’      with: {
  2173в†’        pmType: true,
  2174в†’        train: true,
  2175в†’        assignedTrack: true
  2176в†’      }
  2177в†’    });
  2178в†’    
  2179в†’    if (conflictingPM) {
  2180в†’      return {
  2181в†’        trackId,
  2182в†’        trackNumber: conflictingPM.assignedTrack.trackNumber,
  2183в†’        conflictingPMId: conflictingPM.id,
  2184в†’        conflictingPMCode: conflictingPM.pmType.pmCode,
  2185в†’        conflictingTrainNumber: conflictingPM.train.trainNumber,
  2186в†’        conflictingDateRange: {
  2187в†’          start: conflictingPM.targetDate,
  2188в†’          end: addDays(conflictingPM.targetDate, conflictingPM.pmType.minTrackDays)
  2189в†’        }
  2190в†’      };
  2191в†’    }
  2192в†’    
  2193в†’    return null;
  2194в†’  }
  2195в†’}
