  2254в†’## 4.5 Strategic Planner
  2255в†’
  2256в†’### 4.5.1 Purpose
  2257в†’
  2258в†’Generate and maintain the 1-10 year strategic plan using genetic algorithms, constrained by capacity envelopes from the tactical model.
  2259в†’
  2260в†’### 4.5.2 Implementation
  2261в†’
  2262в†’```typescript
  2263в†’interface StrategicPlannerConfig {
  2264в†’  horizonYears: number;          // 10
  2265в†’  granularity: 'MONTHLY' | 'QUARTERLY';
  2266в†’  populationSize: number;        // 100
  2267в†’  generations: number;           // 500
  2268в†’  mutationRate: number;          // 0.1
  2269в†’  eliteCount: number;            // 10
  2270в†’}
  2271в†’
  2272в†’interface StrategicAllocation {
  2273в†’  trainId: string;
  2274в†’  pmTypeId: string;
  2275в†’  targetQuarter: string;  // e.g., '2028-Q2'
  2276в†’  estimatedHours: number;
  2277в†’  estimatedCost: number;
  2278в†’}
  2279в†’
  2280в†’class StrategicPlanner {
  2281в†’  private constraintAggregation: ConstraintAggregationService;
  2282в†’  
  2283в†’  async generatePlan(
  2284в†’    fromBaseline: string | null
  2285в†’  ): Promise<StrategicPlanResult> {
  2286в†’    // 1. Load current fleet state
  2287в†’    const fleetState = await this.getFleetState();
  2288в†’    
  2289в†’    // 2. Project PM requirements for each train
  2290в†’    const pmRequirements = await this.projectPMRequirements(
  2291в†’      fleetState,
  2292в†’      this.config.horizonYears
  2293в†’    );
  2294в†’    
  2295в†’    // 3. Generate constraint envelopes for each quarter
  2296в†’    const envelopes = await this.generateEnvelopes();
  2297в†’    
  2298в†’    // 4. Run genetic algorithm
  2299в†’    const bestPlan = await this.runGeneticAlgorithm(
  2300в†’      pmRequirements,
  2301в†’      envelopes
  2302в†’    );
  2303в†’    
  2304в†’    // 5. Validate against constraint envelopes
  2305в†’    const validation = await this.validatePlan(bestPlan, envelopes);
  2306в†’    
  2307в†’    if (!validation.valid) {
  2308в†’      // Attempt repair
  2309в†’      const repairedPlan = await this.repairPlan(bestPlan, validation);
  2310в†’      return {
  2311в†’        plan: repairedPlan,
  2312в†’        validation: await this.validatePlan(repairedPlan, envelopes),
  2313в†’        metrics: this.calculateMetrics(repairedPlan)
  2314в†’      };
  2315в†’    }
  2316в†’    
  2317в†’    return {
  2318в†’      plan: bestPlan,
  2319в†’      validation,
  2320в†’      metrics: this.calculateMetrics(bestPlan)
  2321в†’    };
  2322в†’  }
  2323в†’  
  2324в†’  /**
  2325в†’   * Project PM requirements for all trains over the planning horizon.
  2326в†’   * 
  2327в†’   * CRITICAL: This implementation correctly handles:
  2328в†’   * 1. PM hierarchy (C4 satisfies C1/C2/C3 - resets their counters)
  2329в†’   * 2. Dual triggers (mileage OR time, whichever comes first)
  2330в†’   * 3. Recent velocity calculation for accurate projections
  2331в†’   * 4. Cascading projections (each PM feeds into next cycle)
  2332в†’   */
  2333в†’  private async projectPMRequirements(
  2334в†’    fleetState: FleetState,
  2335в†’    horizonYears: number
  2336в†’  ): Promise<PMRequirement[]> {
  2337в†’    const requirements: PMRequirement[] = [];
  2338в†’    const horizonEnd = addYears(new Date(), horizonYears);
  2339в†’    
  2340в†’    for (const train of fleetState.trains) {
  2341в†’      const trainRules = await this.getPMRulesForFleet(train.fleetId);
  2342в†’      const trainHistory = await this.getPMHistoryForTrain(train.id);
  2343в†’      
  2344в†’      // Calculate daily utilization for this train
  2345в†’      const dailyKm = this.calculateDailyUtilization(train, trainHistory);
  2346в†’      
  2347в†’      // Project all PM types for this train
  2348в†’      const trainProjections = await this.projectTrainPMs(
  2349в†’        train,
  2350в†’        trainRules,
  2351в†’        trainHistory,
  2352в†’        horizonEnd,
  2353в†’        dailyKm
  2354в†’      );
  2355в†’      
  2356в†’      requirements.push(...trainProjections);
  2357в†’    }
  2358в†’    
  2359в†’    return requirements;
  2360в†’  }
  2361в†’  
  2362в†’  /**
  2363в†’   * Project all PM events for a single train over the horizon.
  2364в†’   */
  2365в†’  private async projectTrainPMs(
  2366в†’    train: Train,
  2367в†’    pmRules: PMType[],
  2368в†’    pmHistory: PMHistory[],
  2369в†’    horizonEnd: Date,
  2370в†’    dailyKm: number
  2371в†’  ): Promise<PMRequirement[]> {
  2372в†’    const projections: PMRequirement[] = [];
  2373в†’    
  2374в†’    // Create working state (mutable copy of history + projections)
  2375в†’    let workingHistory = [...pmHistory];
  2376в†’    let currentMileage = train.currentMileageKm;
  2377в†’    let currentDate = new Date();
  2378в†’    
  2379в†’    // Project until we exceed horizon
  2380в†’    while (currentDate < horizonEnd) {
  2381в†’      // Find next PM due across all PM types
  2382в†’      let nextPM: { 
  2383в†’        rule: PMType; 
  2384в†’        date: Date; 
  2385в†’        mileage: number; 
  2386в†’        trigger: 'MILEAGE' | 'TIME' 
  2387в†’      } | null = null;
  2388в†’      
  2389в†’      for (const rule of pmRules) {
  2390в†’        const projection = this.calculateNextPMDue(
  2391в†’          train,
  2392в†’          rule,
  2393в†’          pmRules,
  2394в†’          workingHistory,
  2395в†’          currentMileage,
  2396в†’          currentDate,
  2397в†’          dailyKm
  2398в†’        );
