private:
    json generateExplanation(
        const json& train,
        const json& route,
        const json& input,
        const CpSolverResponse& response
    ) {
        json factors = json::array();

        // Mileage balance factor
        int current = train["current_mileage"];
        int target = train["target_mileage"];
        int variance = current - target;

        factors.push_back({
            {"constraint_type", "SOFT"},
            {"constraint_name", "MILEAGE_BALANCE"},
            {"impact", std::abs(variance)},
            {"description", fmt::format(
                "Train is {}km {} fleet target",
                std::abs(variance),
                variance < 0 ? "under" : "over"
            )}
        });

        // Route match factor
        int route_km = route["expected_km"];
        std::string route_advice = "";

        if (variance < -1000 && route_km > 300) {
            route_advice = "High-km route helps balance under-utilized train";
        } else if (variance > 1000 && route_km < 150) {
            route_advice = "Low-km route reduces over-utilization";
        }

        if (!route_advice.empty()) {
            factors.push_back({
                {"constraint_type", "SOFT"},
                {"constraint_name", "ROUTE_MATCH"},
                {"impact", route_km},
                {"description", route_advice}
            });
        }

        // Check if alternatives were blocked
        for (const auto& constraint : input["hard_constraints"]) {
            // Find trains that could have taken this route but were blocked
            factors.push_back({
                {"constraint_type", "HARD"},
                {"constraint_name", constraint["type"]},
                {"impact", 0},
                {"description", fmt::format(
                    "Alternative train {} blocked: {}",
                    constraint["train_id"].get<std::string>().substr(0, 8),
                    constraint["description"].get<std::string>()
                )}
            });
        }

        return factors;
    }
};
